    program_header: $ => seq('program', $.identifier, ';'),
    _command: $ => choice($._composite, $._procedure, $._datatype, $._constrained_type),
    _laurel_type: $ => choice($.int_type, $.bool_type, $.real_type, $.float64_type, $.string_type, $.bv_type, $.core_type, $.map_type, $.identifier),
    _stmt_expr: $ => choice($.boolean, $.number, $.decimal, $.string, $.hole, $.nondet_hole, $.var_decl, $.call, $.new, $.field_access, $.identifier, $.parenthesis, $.assign, $.multi_assign, $.add, $.sub, $.mul, $.div, $.mod, $.div_t, $.mod_t, $.eq, $.neq, $.gt, $.lt, $.le, $.ge, $.and, $.or, $.and_then, $.or_else, $.implies, $.str_concat, $.not, $.neg, $.forall_expr, $.exists_expr, $.if_then_else, $.assert, $.assume, $.return, $.block, $.labelled_block, $.exit, $.while, $.for_loop, $.is_type, $.as_type),
    _type_annotation: $ => $.type_annotation,
