    _invariant_clause: $ => $.invariant_clause,
    _parameter: $ => $.parameter,
    _field: $ => choice($.mutable_field, $.immutable_field),
    _extends: $ => $.extends,
    _composite: $ => $.composite,
    _datatype_constructor_arg: $ => $.datatype_constructor_arg,
    _datatype_constructor: $ => choice($.datatype_constructor, $.identifier),
    _datatype: $ => $.datatype,
    _return_type: $ => $.return_type,
    _invoke_on_clause: $ => $.invoke_on_clause,
    _requires_clause: $ => $.requires_clause,
    _ensures_clause: $ => $.ensures_clause,
    _modifies_clause: $ => choice($.modifies_clause, $.modifies_wildcard),
    _return_parameters: $ => $.return_parameters,
    _opaque_spec: $ => $.opaque_spec,
    _body: $ => choice($.body, $.external_body),
    _procedure: $ => choice($.procedure, $.function),
    _constrained_type: $ => $.constrained_type,
    int_type: $ => 'int',
    bool_type: $ => 'bool',
    real_type: $ => 'real',
    float64_type: $ => 'float64',
    string_type: $ => 'string',
    bv_type: $ => prec.right(1024, seq('bv', $.number)),
