    call: $ => seq($._stmt_expr, '(', commaSep($._stmt_expr), ')'),
    new: $ => prec.right(1024, seq('new', $.identifier)),
    field_access: $ => prec.left(90, seq($._stmt_expr, '#', $.identifier)),
