    add: $ => prec.left(60, seq($._stmt_expr, '+', $._stmt_expr)),
    sub: $ => prec.left(60, seq($._stmt_expr, '-', $._stmt_expr)),
    mul: $ => prec.left(70, seq($._stmt_expr, '*', $._stmt_expr)),
    div: $ => prec.left(70, seq($._stmt_expr, '/', $._stmt_expr)),
