    parameter: $ => prec.left(1024, seq($.identifier, ':', $._laurel_type)),
    mutable_field: $ => seq('var', $.identifier, ':', $._laurel_type),
    immutable_field: $ => seq($.identifier, ':', $._laurel_type),
    is_type: $ => prec.left(40, seq($._stmt_expr, 'is', $.identifier)),
    as_type: $ => prec.left(40, seq($._stmt_expr, 'as', $.identifier)),
    extends: $ => prec.right(1024, seq('extends', commaSep($.identifier))),
    datatype_constructor_arg: $ => prec.left(1024, seq($.identifier, ':', $._laurel_type)),
    datatype_constructor: $ => seq($.identifier, '(', commaSep($._datatype_constructor_arg), ')'),
    datatype: $ => seq('datatype', $.identifier, '{', optional((commaSep($._datatype_constructor))), '}'),
    return_type: $ => prec.right(1024, seq(':', $._laurel_type)),
    invoke_on_clause: $ => prec.right(1024, seq('invokeOn', $._stmt_expr)),
    requires_clause: $ => seq('requires', $._stmt_expr, optional($._error_summary)),
    ensures_clause: $ => seq('ensures', $._stmt_expr, optional($._error_summary)),
    modifies_clause: $ => prec.right(1024, seq('modifies', commaSep($._stmt_expr))),
    modifies_wildcard: $ => seq('modifies', '*'),
    return_parameters: $ => seq('returns', '(', commaSep($._parameter), ')'),
    opaque_spec: $ => seq('opaque', repeat($._ensures_clause), repeat($._modifies_clause)),
    body: $ => prec.right(1024, $._stmt_expr),
    external_body: $ => 'external',
    procedure: $ => seq('procedure', $.identifier, '(', commaSep($._parameter), ')', optional($._return_type), optional($._return_parameters), repeat($._requires_clause), optional($._invoke_on_clause), optional($._opaque_spec), optional($._body), ';'),
    function: $ => seq('function', $.identifier, '(', commaSep($._parameter), ')', optional($._return_type), optional($._return_parameters), repeat($._requires_clause), optional($._invoke_on_clause), optional($._opaque_spec), optional($._body), ';'),
    composite: $ => seq('composite', $.identifier, optional($._extends), '{', repeat($._field), repeat($._procedure), '}'),
    constrained_type: $ => seq('constrained', $.identifier, '=', $.identifier, ':', $._laurel_type, 'where', $._stmt_expr, 'witness', $._stmt_expr),
    comment: $ => token(seq('//', /.*/)),
    identifier: $ => /[A-Za-z_$][A-Za-z0-9_$]*/,
    number: $ => /[0-9]+/,
    decimal: $ => /[0-9]+\.[0-9]+/,
    string: $ => /"([^"\\]|\\.)*"/,
